import base64
import requests
import xml.etree.ElementTree as ET
from urllib.parse import urlencode

class SAMLServiceProvider:
    def __init__(self, entity_id):
        self.entity_id = entity_id

    def build_authn_request(self, destination, user_info):
        root = ET.Element("s:AuthnRequest", {
            "xmlns:s": "urn:oasis:names:tc:SAML:2.0:protocol",
            "ID": self.generate_id(),
            "Version": "2.0",
            "IssueInstant": self.get_current_time(),
            "Destination": destination,
            "AssertionConsumerServiceURL": self.entity_id,
            "ProtocolBinding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
            "Issuer": self.entity_id
        })

        subject = ET.SubElement(root, "s:Subject")
        name_id = ET.SubElement(subject, "s:NameID")
        name_id.text = user_info['name_id']

        return ET.tostring(root, encoding='utf-8', xml_declaration=True)

    def send_authn_request(self, destination, user_info):
        saml_request = self.build_authn_request(destination, user_info)
        encoded_request = base64.b64encode(saml_request).decode('utf-8')
        
        data = {
            'SAMLRequest': encoded_request
        }
        
        response = requests.post(destination, data=data)
        return response

    def generate_id(self):
        import uuid
        return f"_{uuid.uuid4()}"

    def get_current_time(self):
        from datetime import datetime
        return datetime.utcnow().isoformat() + "Z"

